        alert("Aqui vai todos os agendamentos do usuário")
        alert("Entrar em contato com o administrador para cancelar ou alterar agendamento Telefone: (47) 9 9252-3928")
    }
    useEffect(
        () => {
            TodosOsAgendamentos()
            navigation
        }
    )
    return (
        <div>

        </div>
    )
}
